import React from 'react';
// eslint-disable-next-line no-unused-vars
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';

const LandingDetails = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();

    const handleStart = () => {
        localStorage.removeItem('kvti_base_profile');
        localStorage.removeItem('kvti_answers');
        navigate('/diagnosis');
    };

    const fadeInUp = {
        hidden: { opacity: 0, y: 50 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.8, ease: "easeOut" } }
    };

    const staggerContainer = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: {
                staggerChildren: 0.2
            }
        }
    };

    return (
        <div className="w-full relative z-20 bg-slate-50 pb-32 overflow-hidden font-sans">
            {/* Divider / Transition from Hero */}
            <div className="w-full h-32 bg-gradient-to-b from-transparent to-slate-50 absolute top-[-128px] pointer-events-none"></div>

            <div className="max-w-7xl mx-auto px-6 pt-24 space-y-40">

                {/* Step 1: Problem Recognition */}
                <motion.section
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-100px" }}
                    variants={fadeInUp}
                    className="relative w-full max-w-4xl mx-auto text-center"
                >
                    <span className="inline-block px-4 py-1.5 rounded-full border border-rose-200 text-rose-600 bg-rose-50 text-sm font-bold tracking-widest uppercase mb-6 shadow-sm">
                        {t('landing_details.step1_badge')}
                    </span>
                    <h2 className="text-4xl md:text-5xl font-black mb-8 leading-tight whitespace-pre-line text-slate-800 tracking-tight">
                        {t('landing_details.step1_title')}
                    </h2>
                    <p className="text-slate-600 text-lg md:text-xl leading-relaxed font-medium px-4 max-w-3xl mx-auto text-balance">
                        {t('landing_details.step1_desc')}
                    </p>
                </motion.section>

                {/* Step 2: Solution Intro */}
                <motion.section
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-100px" }}
                    variants={fadeInUp}
                    className="relative bg-white rounded-[2rem] p-12 md:p-20 shadow-xl border border-slate-100 flex flex-col md:flex-row items-center gap-16"
                >
                    <div className="flex-1 space-y-8">
                        <div>
                            <span className="text-kvti-primary font-bold tracking-widest text-sm uppercase mb-4 block">
                                {t('landing_details.step2_badge')}
                            </span>
                            <h3 className="text-3xl md:text-4xl font-black text-slate-800 leading-tight">
                                {t('landing_details.step2_title')}
                            </h3>
                        </div>
                        <p className="text-slate-600 text-lg leading-relaxed">
                            {t('landing_details.step2_desc')}
                        </p>
                    </div>
                    <div className="w-full md:w-1/2 flex justify-center">
                        <div className="relative w-64 h-64 bg-slate-50 rounded-full flex items-center justify-center border-4 border-white shadow-2xl">
                            <div className="w-48 h-48 rounded-full bg-gradient-to-tr from-cyan-400 to-blue-500 animate-[spin_8s_linear_infinite] opacity-20 absolute"></div>
                            <div className="w-32 h-32 bg-white rounded-full flex items-center justify-center shadow-inner z-10">
                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 text-kvti-primary">
                                    <path fillRule="evenodd" d="M11.54 22.351l.07.04.028.016a.76.76 0 00.723 0l.028-.015.071-.041a16.975 16.975 0 001.144-.742 19.58 19.58 0 002.683-2.282c1.944-1.99 3.963-4.98 3.963-8.827a8.25 8.25 0 00-16.5 0c0 3.846 2.02 6.837 3.963 8.827a19.58 19.58 0 002.682 2.282 16.975 16.975 0 001.145.742zM12 13.5a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
                                </svg>
                            </div>
                        </div>
                    </div>
                </motion.section>

                {/* Step 3: Multi-dimensional Vector Analysis */}
                <motion.section
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-100px" }}
                    variants={fadeInUp}
                    className="relative w-full flex flex-col items-center"
                >
                    <div className="text-center mb-16 max-w-3xl">
                        <span className="inline-block px-4 py-1.5 rounded-full border border-indigo-200 text-indigo-600 bg-indigo-50 text-sm font-bold tracking-widest uppercase mb-6 shadow-sm">
                            {t('landing_details.step3_badge')}
                        </span>
                        <h2 className="text-4xl font-black mb-6 text-slate-800 tracking-tight">
                            {t('landing_details.step3_title')}
                        </h2>
                        <p className="text-slate-600 text-lg leading-relaxed text-balance">
                            {t('landing_details.step3_desc')}
                        </p>
                    </div>

                    {/* The Vector Visualization */}
                    <div className="w-full max-w-4xl h-[400px] bg-white rounded-3xl shadow-lg border border-slate-100 flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(99,102,241,0.05)_0,transparent_100%)]"></div>

                        <div className="relative w-80 h-80">
                            {/* Axis lines */}
                            <div className="absolute top-1/2 left-0 w-full h-[1px] bg-slate-200"></div>
                            <div className="absolute top-0 left-1/2 w-[1px] h-full bg-slate-200"></div>
                            <div className="absolute top-0 left-0 w-full h-full border-[1px] rounded-full border-slate-200 border-dashed"></div>
                            <div className="absolute top-[15%] left-[15%] w-[70%] h-[70%] border-[1px] rounded-full border-slate-200 border-dashed"></div>

                            {/* Polygon Vector representing RIASEC */}
                            <svg className="absolute inset-0 w-full h-full transform -rotate-90 origin-center opacity-80" viewBox="0 0 100 100">
                                <polygon points="50,10 85,30 90,70 50,95 20,65 15,25" fill="rgba(99,102,241,0.2)" stroke="rgb(99,102,241)" strokeWidth="1.5" />
                                <circle cx="50" cy="10" r="2" fill="rgb(99,102,241)" />
                                <circle cx="85" cy="30" r="2" fill="rgb(99,102,241)" />
                                <circle cx="90" cy="70" r="2" fill="rgb(99,102,241)" />
                                <circle cx="50" cy="95" r="2" fill="rgb(99,102,241)" />
                                <circle cx="20" cy="65" r="2" fill="rgb(99,102,241)" />
                                <circle cx="15" cy="25" r="2" fill="rgb(99,102,241)" />
                            </svg>

                            {/* Center node */}
                            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 bg-indigo-600 rounded-full shadow-[0_0_15px_rgba(79,70,229,0.5)]"></div>
                        </div>
                    </div>
                </motion.section>

                {/* Step 4: Target Audience */}
                <motion.section
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-100px" }}
                    variants={fadeInUp}
                    className="w-full max-w-5xl mx-auto"
                >
                    <div className="text-center mb-16">
                        <span className="inline-block px-4 py-1.5 rounded-full border border-teal-200 text-teal-600 bg-teal-50 text-sm font-bold tracking-widest uppercase mb-6 shadow-sm">
                            {t('landing_details.step4_badge')}
                        </span>
                        <h2 className="text-4xl font-black text-slate-800 tracking-tight whitespace-pre-line">
                            {t('landing_details.step4_title')}
                        </h2>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {['t1', 't2', 't3'].map((item, idx) => (
                            <motion.div
                                key={idx}
                                variants={fadeInUp}
                                className="bg-white rounded-2xl p-8 shadow-md border border-slate-100 hover:shadow-xl transition-shadow duration-300 group"
                            >
                                <div className="w-12 h-12 rounded-xl bg-teal-50 flex items-center justify-center text-teal-600 mb-6 group-hover:scale-110 transition-transform">
                                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-6 h-6">
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                                    </svg>
                                </div>
                                <p className="text-slate-600 leading-relaxed font-medium">
                                    {t(`landing_details.step4_${item}`)}
                                </p>
                            </motion.div>
                        ))}
                    </div>
                </motion.section>

                {/* Section 5: Call to Action (Final) */}
                <motion.section
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-100px" }}
                    variants={fadeInUp}
                    className="text-center py-24 relative bg-gradient-to-b from-white to-slate-100 rounded-[3rem] shadow-sm border border-slate-200"
                >
                    <h2 className="text-4xl md:text-5xl font-black mb-12 leading-tight whitespace-pre-line text-slate-800 tracking-tight">
                        {t('landing_details.cta_title')}
                    </h2>
                    <button
                        onClick={handleStart}
                        className="relative inline-flex items-center justify-center px-14 py-5 text-xl font-bold text-white transition-all duration-300 bg-kvti-primary hover:bg-blue-600 hover:shadow-xl rounded-full hover:-translate-y-1"
                    >
                        <span className="flex items-center gap-3">
                            {t('landing_details.cta_button')}
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                            </svg>
                        </span>
                    </button>
                </motion.section>

            </div>
        </div>
    );
};

export default LandingDetails;
